#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <cuda_runtime.h>
#include <stdint.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_kernel(const T * __restrict__ mask,
                              const T * __restrict__ in,
                              T * __restrict__ out,
                              const int input_width,
                              const int mask_width)
{
  int i = blockIdx.x * blockDim.x + threadIdx.x;
  if (i < input_width) {
    int start = i - mask_width / 2;
    T s = 0;
    for (int j = 0; j < mask_width; j++) {
      if (0 <= start + j && input_width > start + j) {
        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_kernel(const T *__restrict__ mask,
                                    const T *__restrict__ in,
                                    T *__restrict__ out,
                                    const int input_width,
                                    const int mask_width)
{
  T tile[BLOCK_SIZE + MAX_MASK_WIDTH - 1];
  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = blockDim.x;
  int i = bid * dim + lid;

  int n = mask_width / 2;

  // Load left halo
  int halo_left = (bid - 1) * dim + lid;
  if (dim - n <= lid)
    tile[lid - (dim - n)] = (0 > halo_left || halo_left >= input_width) ? 0 : in[halo_left];

  // Load center
  tile[n + lid] = (i >= input_width) ? 0 : in[i];

  // Load right halo
  int halo_right = (bid + 1) * dim + lid;
  if (n > lid)
    tile[lid + dim + n] = (input_width <= halo_right || halo_right < 0) ? 0 : in[halo_right];

  __syncthreads();

  if (i < input_width) {
    T s = 0;
    for (int j = 0; j < mask_width; j++)
      s += tile[lid + j] * mask[j];
    out[i] = s;
  }
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_caching_kernel(const T *__restrict__ mask,
                                            const T *__restrict__ in,
                                            T *__restrict__ out,
                                            const int input_width,
                                            const int mask_width)
{
  T tile[BLOCK_SIZE];
  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = blockDim.x;
  int i = bid * dim + lid;

  tile[lid] = (i >= input_width) ? 0 : in[i];

  __syncthreads();

  if (i < input_width) {
    int this_tile_start = bid * dim;
    int next_tile_start = (bid + 1) * dim;
    int start = i - (mask_width / 2);
    T s = 0;
    for (int j = 0; j < mask_width; j++) {
      int in_index = start + j;
      if (0 <= in_index && input_width > in_index) {
        if (this_tile_start <= in_index && next_tile_start > in_index) {
          s += tile[lid + j - (mask_width / 2)] * mask[j];
        } else {
          s += in[in_index] * mask[j];
        }
      }
    }
    out[i] = s;
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (0 <= start + j && input_width > start + j) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  T *d_a, *d_b, *d_mask;

  a = (T *)malloc(size_bytes);
  b = (T *)malloc(size_bytes);

  T mask[MAX_MASK_WIDTH];
  for (int i = 0; i < MAX_MASK_WIDTH; i++) mask[i] = 1;

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  cudaMalloc(&d_a, size_bytes);
  cudaMalloc(&d_b, size_bytes);
  cudaMalloc(&d_mask, mask_width * sizeof(T));

  cudaMemcpy(d_a, a, size_bytes, cudaMemcpyHostToDevice);
  cudaMemcpy(d_mask, mask, mask_width * sizeof(T), cudaMemcpyHostToDevice);

  int num_blocks = input_width / MAX_BLOCK_SIZE;

  // conv1d tests
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs *= 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d_kernel<T, 64><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  128: {conv1d_kernel<T, 128><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  256: {conv1d_kernel<T, 256><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  512: {conv1d_kernel<T, 512><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case 1024: {conv1d_kernel<T, 1024><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
      }
    }
    cudaDeviceSynchronize();
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel: %f (us)\n",
           (time * 1e-3f) / repeat);
    cudaMemcpy(b, d_b, size_bytes, cudaMemcpyDeviceToHost);
    reference(a, b, mask, input_width, mask_width);
  }

  // conv1d_tiled tests
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs *= 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d_tiled_kernel<T, 64><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  128: {conv1d_tiled_kernel<T, 128><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  256: {conv1d_tiled_kernel<T, 256><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  512: {conv1d_tiled_kernel<T, 512><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case 1024: {conv1d_tiled_kernel<T, 1024><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
      }
    }
    cudaDeviceSynchronize();
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel: %f (us)\n",
           (time * 1e-3f) / repeat);
    cudaMemcpy(b, d_b, size_bytes, cudaMemcpyDeviceToHost);
    reference(a, b, mask, input_width, mask_width);
  }

  // conv1d_tiled_caching tests
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs *= 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      switch(bs) {
        case   64: {conv1d_tiled_caching_kernel<T, 64><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  128: {conv1d_tiled_caching_kernel<T, 128><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  256: {conv1d_tiled_caching_kernel<T, 256><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case  512: {conv1d_tiled_caching_kernel<T, 512><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
        case 1024: {conv1d_tiled_caching_kernel<T, 1024><<<num_blocks, bs>>>(d_mask, d_a, d_b, input_width, mask_width); break;}
      }
    }
    cudaDeviceSynchronize();
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel: %f (us)\n",
           (time * 1e-3f) / repeat);
    cudaMemcpy(b, d_b, size_bytes, cudaMemcpyDeviceToHost);
    reference(a, b, mask, input_width, mask_width);
  }

  cudaFree(d_a);
  cudaFree(d_b);
  cudaFree(d_mask);
  free(a);
  free(b);
}

int main(int argc, char* argv[]) {
  if (3 != argc) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int item_1 = atoi(argv[1]);
  item_1 = (item_1 + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;
  const int var_2 = atoi(argv[2]);

  for (int data_0 = 3; data_0 < MAX_MASK_WIDTH; data_0 += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", data_0);

    printf("1D convolution (FP64)\n");
    conv1D<double>(item_1, data_0, var_2);

    printf("1D convolution (FP32)\n");
    conv1D<float>(item_1, data_0, var_2);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(item_1, data_0, var_2);
  }

  return 0;
}
